import React, { useState, useRef, useEffect } from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';

// ─── Notifications ────────────────────────────────────────────────────────────
const NOTIFICATIONS = [
  { id:1, icon:'❤️', title:'Heart Rate Normal',          desc:'Resting heart rate is 72 bpm — within healthy range.',            time:'2 min ago', type:'good', tag:'Heart'    },
  { id:2, icon:'😴', title:'Sleep Goal Not Met',          desc:'You only slept 5.5 hrs last night. Try to aim for 8 hrs tonight.', time:'1 hr ago',  type:'warn', tag:'Sleep'    },
  { id:3, icon:'🔥', title:'Calorie Goal Almost Reached', desc:"You're at 72% of your daily calorie burn goal. Keep it up!",       time:'3 hr ago',  type:'info', tag:'Calories' },
  { id:4, icon:'🧠', title:'Stress Level Elevated',       desc:'HRV indicates moderate stress today. A short walk may help.',      time:'5 hr ago',  type:'warn', tag:'Stress'   },
  { id:5, icon:'👟', title:'Step Goal Achieved!',         desc:'You hit 9,158 steps today — 91% of your daily goal. Great work!',  time:'6 hr ago',  type:'good', tag:'Steps'    },
];
const NS = {
  good: { dot:'#34d399', glow:'rgba(52,211,153,0.6)',  bg:'rgba(52,211,153,0.07)',  border:'rgba(52,211,153,0.2)',  tag:{color:'#34d399',bg:'rgba(52,211,153,0.12)',border:'rgba(52,211,153,0.25)'} },
  warn: { dot:'#fbbf24', glow:'rgba(251,191,36,0.6)',  bg:'rgba(251,191,36,0.07)',  border:'rgba(251,191,36,0.2)',  tag:{color:'#fbbf24',bg:'rgba(251,191,36,0.12)',border:'rgba(251,191,36,0.25)'} },
  info: { dot:'#60a5fa', glow:'rgba(96,165,250,0.6)',  bg:'rgba(96,165,250,0.07)',  border:'rgba(96,165,250,0.2)',  tag:{color:'#60a5fa',bg:'rgba(96,165,250,0.12)',border:'rgba(96,165,250,0.25)'} },
};

// ─── Devices ──────────────────────────────────────────────────────────────────
const INIT_DEVICES = [
  { id:'apple',   name:'Apple Watch',    img:'/devices/apple-watch.png',   desc:'Series 9 · watchOS 10',      color:'#60a5fa', connected:true  },
  { id:'fitbit',  name:'Fitbit Sense 2', img:'/devices/fitbit.png',        desc:'Firmware 1.187.48',           color:'#34d399', connected:false },
  { id:'samsung', name:'Galaxy Watch 6', img:'/devices/samsung-watch.png', desc:'Wear OS 4 · One UI Watch 6',  color:'#a78bfa', connected:false },
  { id:'whoop',   name:'WHOOP 4.0',      img:'/devices/whoop.png',         desc:'Fitness & Recovery Tracker',  color:'#f87171', connected:false },
];
const NEW_DEVICES = [
  { id:'oura',     name:'Oura Ring Gen 3',   img:'/devices/oura.png',     desc:'Sleep & Recovery Ring',      color:'#fbbf24' },
  { id:'garmin',   name:'Garmin Fenix 7',    img:'/devices/garmin.png',   desc:'GPS Multisport Watch',       color:'#34d399' },
  { id:'polar',    name:'Polar H10',         img:'/devices/polar.png',    desc:'Heart Rate Sensor',          color:'#f87171' },
  { id:'withings', name:'Withings ScanWatch',img:'/devices/withings.png', desc:'Hybrid Smartwatch + ECG',    color:'#60a5fa' },
];

const SHARED_STYLES = `
  @keyframes notifDropIn {
    from { opacity:0; transform:translateY(-10px) scale(0.95); }
    to   { opacity:1; transform:translateY(0) scale(1); }
  }
  @keyframes centrePopIn {
    from { opacity:0; transform:translate(-50%,-48%) scale(0.93); }
    to   { opacity:1; transform:translate(-50%,-50%) scale(1); }
  }
  @keyframes spin { to { transform:rotate(360deg); } }
  .notif-scroll::-webkit-scrollbar,
  .sync-scroll::-webkit-scrollbar  { width:5px; }
  .notif-scroll::-webkit-scrollbar-track,
  .sync-scroll::-webkit-scrollbar-track  { background:transparent; }
  .notif-scroll::-webkit-scrollbar-thumb,
  .sync-scroll::-webkit-scrollbar-thumb  { background:rgba(91,184,255,0.2); border-radius:4px; }
  .notif-scroll::-webkit-scrollbar-thumb:hover,
  .sync-scroll::-webkit-scrollbar-thumb:hover { background:rgba(91,184,255,0.4); }
`;

// ─── Device row ───────────────────────────────────────────────────────────────
const DeviceRow = ({ dev, actionLabel, actionColor, onAction, isSyncing, isConnected, method }) => (
  <div style={{
    display:'flex', alignItems:'center', gap:'1.1rem',
    padding:'1.05rem 1.2rem', borderRadius:20,
    background: isConnected ? `${dev.color}0f` : 'rgba(255,255,255,0.03)',
    border:`1px solid ${isConnected ? dev.color+'33' : 'rgba(255,255,255,0.07)'}`,
    transition:'all 0.2s',
  }}>
    <div style={{
      width:52, height:52, borderRadius:16, flexShrink:0,
      background: isConnected ? `${dev.color}22` : 'rgba(255,255,255,0.05)',
      border:`1px solid ${isConnected ? dev.color+'44' : 'rgba(255,255,255,0.1)'}`,
      display:'flex', alignItems:'center', justifyContent:'center',
      boxShadow: isConnected ? `0 0 16px ${dev.color}44` : 'none',
      overflow:'hidden', transition:'all 0.2s',
    }}>
      <img src={dev.img} alt={dev.name} style={{ width:34, height:34, objectFit:'contain' }}
        onError={e => {
          e.target.style.display='none';
          e.target.parentNode.innerHTML=`<span style="font-size:0.68rem;font-weight:800;color:${dev.color}">${dev.name.slice(0,2).toUpperCase()}</span>`;
        }} />
    </div>

    <div style={{ flex:1, minWidth:0 }}>
      <div style={{ fontSize:'0.92rem', fontWeight:700, color: isConnected ? '#fff' : '#c8dff0', marginBottom:3 }}>{dev.name}</div>
      <div style={{ fontSize:'0.72rem', color:'#3d6b8a', lineHeight:1.4 }}>{dev.desc}</div>
      {isConnected && (
        <div style={{ display:'flex', alignItems:'center', gap:6, marginTop:5 }}>
          <div style={{ width:7, height:7, borderRadius:'50%', background:'#34d399', boxShadow:'0 0 6px #34d399' }} />
          <span style={{ fontSize:'0.65rem', color:'#34d399', fontWeight:700 }}>
            Connected via {method==='bt' ? 'Bluetooth' : 'Phone App'} · Syncing
          </span>
        </div>
      )}
    </div>

    <button onClick={onAction} disabled={isSyncing} style={{
      flexShrink:0, padding:'0.5rem 1.15rem', borderRadius:20,
      border:`1px solid ${actionColor}55`, background:`${actionColor}18`,
      color: actionColor, fontWeight:700, fontSize:'0.74rem',
      cursor: isSyncing ? 'default' : 'pointer',
      transition:'all 0.2s', whiteSpace:'nowrap', letterSpacing:'0.04em',
      display:'flex', alignItems:'center', gap:'0.4rem',
    }}
      onMouseEnter={e=>{ if(!isSyncing) e.currentTarget.style.transform='scale(1.06)'; }}
      onMouseLeave={e=>{ e.currentTarget.style.transform='scale(1)'; }}
    >
      {isSyncing && <span style={{ display:'inline-block', width:13, height:13, border:`2px solid ${actionColor}`, borderTopColor:'transparent', borderRadius:'50%', animation:'spin 0.7s linear infinite' }} />}
      {isSyncing ? 'Connecting…' : actionLabel}
    </button>
  </div>
);

// ─── Connection method picker (shown when user clicks + Add on a new device) ──
const ConnectMethodPicker = ({ dev, onConnect, onBack }) => {
  const [chosen, setChosen] = useState(null); // 'bt' | 'phone'
  const [pairing, setPairing] = useState(false);
  const [done, setDone]       = useState(false);

  const handlePair = () => {
    if (!chosen) return;
    setPairing(true);
    setTimeout(() => { setPairing(false); setDone(true); }, 2000);
    setTimeout(() => { onConnect(chosen); }, 2600);
  };

  const MethodCard = ({ id, title, subtitle, icon }) => {
    const active = chosen === id;
    return (
      <div onClick={() => !done && setChosen(id)} style={{
        flex:1, padding:'1.1rem', borderRadius:18, cursor: done ? 'default' : 'pointer',
        background: active ? `${dev.color}18` : 'rgba(255,255,255,0.03)',
        border:`2px solid ${active ? dev.color : 'rgba(255,255,255,0.08)'}`,
        display:'flex', flexDirection:'column', alignItems:'center', gap:'0.6rem',
        transition:'all 0.2s',
        boxShadow: active ? `0 0 20px ${dev.color}33` : 'none',
      }}>
        <div style={{
          width:52, height:52, borderRadius:16,
          background: active ? `${dev.color}25` : 'rgba(255,255,255,0.06)',
          border:`1px solid ${active ? dev.color+'55' : 'rgba(255,255,255,0.1)'}`,
          display:'flex', alignItems:'center', justifyContent:'center', fontSize:'1.5rem',
        }}>{icon}</div>
        <div style={{ textAlign:'center' }}>
          <div style={{ fontSize:'0.85rem', fontWeight:700, color: active ? '#fff' : '#a8c8e0', marginBottom:3 }}>{title}</div>
          <div style={{ fontSize:'0.68rem', color:'#3d6b8a', lineHeight:1.5 }}>{subtitle}</div>
        </div>
        {active && (
          <div style={{
            width:20, height:20, borderRadius:'50%',
            background: dev.color, display:'flex', alignItems:'center', justifyContent:'center',
            fontSize:'0.7rem', color:'#fff', fontWeight:900,
            boxShadow:`0 0 10px ${dev.color}88`,
          }}>✓</div>
        )}
      </div>
    );
  };

  return (
    <div style={{ display:'flex', flexDirection:'column', gap:'1rem' }}>
      {/* Back + device name */}
      <div style={{ display:'flex', alignItems:'center', gap:'0.75rem' }}>
        <button onClick={onBack} style={{
          background:'rgba(255,255,255,0.06)', border:'1px solid rgba(255,255,255,0.12)',
          borderRadius:10, padding:'0.3rem 0.75rem', color:'#5a88a8',
          fontSize:'0.72rem', fontWeight:700, cursor:'pointer', transition:'all 0.15s',
        }}
          onMouseEnter={e=>e.currentTarget.style.color='#fff'}
          onMouseLeave={e=>e.currentTarget.style.color='#5a88a8'}
        >← Back</button>
        <div style={{ display:'flex', alignItems:'center', gap:'0.6rem' }}>
          <div style={{
            width:32, height:32, borderRadius:10, overflow:'hidden',
            background:`${dev.color}22`, border:`1px solid ${dev.color}44`,
            display:'flex', alignItems:'center', justifyContent:'center',
          }}>
            <img src={dev.img} alt={dev.name} style={{ width:22, height:22, objectFit:'contain' }}
              onError={e=>{ e.target.style.display='none'; e.target.parentNode.innerHTML=`<span style="font-size:0.6rem;font-weight:800;color:${dev.color}">${dev.name.slice(0,2).toUpperCase()}</span>`; }} />
          </div>
          <span style={{ fontSize:'0.88rem', fontWeight:700, color:'#fff' }}>{dev.name}</span>
        </div>
      </div>

      <div style={{ fontSize:'0.75rem', color:'#3d6b8a', fontWeight:600 }}>Choose how to connect:</div>

      {/* Two method cards */}
      <div style={{ display:'flex', gap:'0.75rem' }}>
        <MethodCard id="bt"    title="Bluetooth" subtitle="Connect directly via Bluetooth Low Energy" icon="📶" />
        <MethodCard id="phone" title="Connect via Phone" subtitle="Sync through your phone's companion app" icon="📱" />
      </div>

      {/* BT instructions */}
      {chosen === 'bt' && !done && (
        <div style={{
          padding:'0.85rem 1rem', borderRadius:14,
          background:'rgba(91,184,255,0.06)', border:'1px solid rgba(91,184,255,0.18)',
          fontSize:'0.72rem', color:'#5a88a8', lineHeight:1.7,
        }}>
          1. Make sure <strong style={{color:'#c8dff0'}}>{dev.name}</strong> is powered on and nearby<br/>
          2. Put the device into pairing mode<br/>
          3. Tap <strong style={{color:'#c8dff0'}}>Pair via Bluetooth</strong> below to start scanning
        </div>
      )}

      {/* Phone instructions */}
      {chosen === 'phone' && !done && (
        <div style={{
          padding:'0.85rem 1rem', borderRadius:14,
          background:'rgba(167,139,250,0.06)', border:'1px solid rgba(167,139,250,0.18)',
          fontSize:'0.72rem', color:'#5a88a8', lineHeight:1.7,
        }}>
          1. Open the <strong style={{color:'#c8dff0'}}>{dev.name.split(' ')[0]} companion app</strong> on your phone<br/>
          2. Make sure the device is paired in the app<br/>
          3. Tap <strong style={{color:'#c8dff0'}}>Connect via Phone</strong> below to link your account
        </div>
      )}

      {/* Done banner */}
      {done && (
        <div style={{
          padding:'0.85rem 1rem', borderRadius:14,
          background:'rgba(52,211,153,0.1)', border:'1px solid rgba(52,211,153,0.3)',
          display:'flex', alignItems:'center', gap:'0.6rem',
          fontSize:'0.78rem', color:'#34d399', fontWeight:700,
        }}>
          <div style={{ width:8, height:8, borderRadius:'50%', background:'#34d399', boxShadow:'0 0 8px #34d399' }} />
          {dev.name} connected successfully! Redirecting…
        </div>
      )}

      {/* Pair button */}
      {!done && (
        <button onClick={handlePair} disabled={!chosen || pairing} style={{
          width:'100%', padding:'0.8rem',
          background: chosen
            ? `linear-gradient(135deg,${dev.color}44,${dev.color}22)`
            : 'rgba(255,255,255,0.04)',
          border:`1px solid ${chosen ? dev.color+'55' : 'rgba(255,255,255,0.08)'}`,
          borderRadius:14, color: chosen ? '#fff' : '#3d6b8a',
          fontWeight:800, fontSize:'0.88rem', cursor: chosen ? 'pointer' : 'default',
          transition:'all 0.2s', letterSpacing:'0.04em',
          display:'flex', alignItems:'center', justifyContent:'center', gap:'0.5rem',
          boxShadow: chosen ? `0 4px 20px ${dev.color}33` : 'none',
        }}
          onMouseEnter={e=>{ if(chosen && !pairing) e.currentTarget.style.transform='translateY(-1px)'; }}
          onMouseLeave={e=>{ e.currentTarget.style.transform='translateY(0)'; }}
        >
          {pairing && <span style={{ display:'inline-block', width:14, height:14, border:`2px solid #fff`, borderTopColor:'transparent', borderRadius:'50%', animation:'spin 0.7s linear infinite' }} />}
          {pairing ? 'Pairing…' : chosen === 'bt' ? '📶 Pair via Bluetooth' : chosen === 'phone' ? '📱 Connect via Phone' : 'Select a connection method'}
        </button>
      )}
    </div>
  );
};

// ─── Sync Modal ───────────────────────────────────────────────────────────────
const SyncModal = ({ onClose }) => {
  const [tab, setTab]           = useState('my');
  const [devices, setDevices]   = useState(INIT_DEVICES);
  const [syncing, setSyncing]   = useState(null);
  const [picking, setPicking]   = useState(null); // device being configured

  const handleToggle = (id) => {
    const dev = devices.find(d => d.id === id);
    if (dev.connected) {
      setDevices(prev => prev.map(d => d.id===id ? {...d, connected:false, method:null} : d));
    } else {
      setSyncing(id);
      setTimeout(() => { setDevices(prev => prev.map(d => d.id===id ? {...d, connected:true} : d)); setSyncing(null); }, 1800);
    }
  };

  const handlePickMethod = (dev) => setPicking(dev);

  const handleConnect = (dev, method) => {
    setDevices(prev => {
      const exists = prev.find(d => d.id === dev.id);
      if (exists) return prev.map(d => d.id===dev.id ? {...d, connected:true, method} : d);
      return [...prev, {...dev, connected:true, method}];
    });
    setPicking(null);
    setTab('my');
  };

  const connected = devices.filter(d => d.connected).length;

  const TabBtn = ({ k, label }) => (
    <button onClick={() => { setTab(k); setPicking(null); }} style={{
      flex:1, padding:'0.65rem 0', fontWeight:700, fontSize:'0.82rem',
      border:'none', borderRadius:10, cursor:'pointer', letterSpacing:'0.04em',
      transition:'all 0.18s',
      background: tab===k ? 'linear-gradient(135deg,rgba(91,184,255,0.2),rgba(52,211,153,0.1))' : 'transparent',
      color: tab===k ? '#fff' : '#3d6b8a',
      borderBottom: tab===k ? '2px solid #5bb8ff' : '2px solid transparent',
    }}>{label}</button>
  );

  return (
    <>
      <div onClick={onClose} style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.55)', backdropFilter:'blur(6px)', zIndex:9998 }} />

      <div style={{
        position:'fixed', top:'50%', left:'50%', transform:'translate(-50%,-50%)',
        width:'min(640px, 92vw)', maxHeight:'88vh',
        background:'linear-gradient(160deg,#0c1e30 0%,#0f2840 50%,#0c1e30 100%)',
        border:'1px solid rgba(91,184,255,0.22)', borderRadius:28,
        boxShadow:'0 40px 100px rgba(0,0,0,0.8)',
        zIndex:9999, overflow:'hidden', display:'flex', flexDirection:'column',
        animation:'centrePopIn 0.28s cubic-bezier(0.34,1.56,0.64,1)',
      }}>
        <div style={{ height:3, background:'linear-gradient(90deg,transparent,#34d399,#60a5fa,#34d399,transparent)', opacity:0.9, flexShrink:0 }} />

        {/* Header */}
        <div style={{
          display:'flex', alignItems:'center', justifyContent:'space-between',
          padding:'1.5rem 1.8rem 1.2rem',
          borderBottom:'1px solid rgba(91,184,255,0.1)',
          background:'rgba(52,211,153,0.03)', flexShrink:0,
        }}>
          <div style={{ display:'flex', alignItems:'center', gap:'1rem' }}>
            <div style={{ width:48, height:48, borderRadius:15, background:'transparent', border:'none', display:'flex', alignItems:'center', justifyContent:'center', overflow:'hidden' }}>
              <img src="/fitness-tracker.png" alt="Sync"
                style={{ width:34, height:34, objectFit:'contain', filter:'drop-shadow(0 0 8px rgba(91,184,255,0.9)) drop-shadow(0 0 18px rgba(91,184,255,0.5))' }}
                onError={e=>e.target.style.display='none'} />
            </div>
            <div>
              <div style={{ fontWeight:800, fontSize:'1.15rem', color:'#fff', lineHeight:1.2 }}>Sync Devices</div>
              <div style={{ fontSize:'0.75rem', color:'#5a88a8', marginTop:3 }}>
                {connected > 0
                  ? <span style={{ color:'#34d399', fontWeight:600 }}>{connected} device{connected>1?'s':''} connected</span>
                  : <span style={{ color:'#5a88a8', fontWeight:600 }}>No devices connected</span>}
              </div>
            </div>
          </div>
          <button onClick={onClose} style={{
            background:'rgba(255,255,255,0.06)', border:'1px solid rgba(255,255,255,0.12)',
            borderRadius:'50%', width:36, height:36, color:'#5a88a8', fontSize:'0.9rem',
            cursor:'pointer', display:'flex', alignItems:'center', justifyContent:'center', transition:'all 0.15s',
          }}
            onMouseEnter={e=>{ e.currentTarget.style.background='rgba(255,255,255,0.14)'; e.currentTarget.style.color='#fff'; }}
            onMouseLeave={e=>{ e.currentTarget.style.background='rgba(255,255,255,0.06)'; e.currentTarget.style.color='#5a88a8'; }}
          >✕</button>
        </div>

        {/* Tabs */}
        <div style={{
          display:'flex', gap:'0.3rem', padding:'0.85rem 1.4rem 0',
          borderBottom:'1px solid rgba(255,255,255,0.06)',
          background:'rgba(255,255,255,0.01)', flexShrink:0,
        }}>
          <TabBtn k="my"  label="My Devices" />
          <TabBtn k="new" label="+ Connect New Device" />
        </div>

        {/* Scrollable body */}
        <div className="sync-scroll" style={{ overflowY:'auto', padding:'1rem 1.4rem', flex:1 }}>

          {/* MY DEVICES */}
          {tab==='my' && (
            <div style={{ display:'flex', flexDirection:'column', gap:'0.6rem' }}>
              {devices.length===0 && (
                <div style={{ textAlign:'center', padding:'3rem', color:'#3d6b8a', fontSize:'0.82rem' }}>
                  No devices added yet. Switch to "+ Connect New Device".
                </div>
              )}
              {devices.map(dev => (
                <DeviceRow key={dev.id} dev={dev}
                  isConnected={dev.connected} isSyncing={syncing===dev.id}
                  method={dev.method}
                  actionLabel={dev.connected ? 'Disconnect' : '+ Connect'}
                  actionColor={dev.connected ? '#f87171' : dev.color}
                  onAction={() => handleToggle(dev.id)}
                />
              ))}
            </div>
          )}

          {/* CONNECT NEW */}
          {tab==='new' && !picking && (
            <div style={{ display:'flex', flexDirection:'column', gap:'0.6rem' }}>
              <p style={{ fontSize:'0.75rem', color:'#3d6b8a', margin:'0 0 0.4rem 0.2rem' }}>
                Select a device to choose how to connect
              </p>
              {NEW_DEVICES.map(dev => {
                const alreadyAdded = !!devices.find(d => d.id===dev.id && d.connected);
                return (
                  <div key={dev.id} style={{
                    display:'flex', alignItems:'center', gap:'1.1rem',
                    padding:'1.05rem 1.2rem', borderRadius:20,
                    background: alreadyAdded ? `${dev.color}0f` : 'rgba(255,255,255,0.03)',
                    border:`1px solid ${alreadyAdded ? dev.color+'33' : 'rgba(255,255,255,0.07)'}`,
                  }}>
                    <div style={{
                      width:52, height:52, borderRadius:16, flexShrink:0,
                      background:`${dev.color}18`, border:`1px solid ${dev.color}33`,
                      display:'flex', alignItems:'center', justifyContent:'center', overflow:'hidden',
                    }}>
                      <img src={dev.img} alt={dev.name} style={{ width:34, height:34, objectFit:'contain' }}
                        onError={e=>{ e.target.style.display='none'; e.target.parentNode.innerHTML=`<span style="font-size:0.68rem;font-weight:800;color:${dev.color}">${dev.name.slice(0,2).toUpperCase()}</span>`; }} />
                    </div>
                    <div style={{ flex:1, minWidth:0 }}>
                      <div style={{ fontSize:'0.92rem', fontWeight:700, color:'#e2e8f0', marginBottom:3 }}>{dev.name}</div>
                      <div style={{ fontSize:'0.72rem', color:'#3d6b8a' }}>{dev.desc}</div>
                    </div>
                    <button onClick={() => !alreadyAdded && handlePickMethod(dev)} disabled={alreadyAdded} style={{
                      flexShrink:0, padding:'0.5rem 1.15rem', borderRadius:20,
                      border:`1px solid ${alreadyAdded ? 'rgba(52,211,153,0.4)' : dev.color+'55'}`,
                      background: alreadyAdded ? 'rgba(52,211,153,0.12)' : `${dev.color}18`,
                      color: alreadyAdded ? '#34d399' : dev.color,
                      fontWeight:700, fontSize:'0.74rem', cursor: alreadyAdded ? 'default' : 'pointer',
                      transition:'all 0.2s', whiteSpace:'nowrap', letterSpacing:'0.04em',
                    }}
                      onMouseEnter={e=>{ if(!alreadyAdded) e.currentTarget.style.transform='scale(1.06)'; }}
                      onMouseLeave={e=>{ e.currentTarget.style.transform='scale(1)'; }}
                    >{alreadyAdded ? '✓ Added' : '+ Add'}</button>
                  </div>
                );
              })}
            </div>
          )}

          {/* METHOD PICKER */}
          {tab==='new' && picking && (
            <ConnectMethodPicker
              dev={picking}
              onConnect={(method) => handleConnect(picking, method)}
              onBack={() => setPicking(null)}
            />
          )}
        </div>

        {/* Footer */}
        <div style={{
          padding:'1rem 1.4rem 1.2rem',
          borderTop:'1px solid rgba(91,184,255,0.1)',
          background:'rgba(52,211,153,0.02)',
          display:'flex', alignItems:'center', justifyContent:'space-between', gap:'1rem',
          flexShrink:0,
        }}>
          <span style={{ fontSize:'0.72rem', color:'#3d6b8a' }}>🔒 Data is encrypted end-to-end</span>
          <button style={{
            padding:'0.6rem 1.5rem',
            background:'linear-gradient(135deg,rgba(52,211,153,0.22),rgba(96,165,250,0.14))',
            border:'1px solid rgba(52,211,153,0.35)', borderRadius:14,
            color:'#34d399', fontWeight:800, fontSize:'0.82rem',
            cursor:'pointer', transition:'all 0.18s', letterSpacing:'0.04em', whiteSpace:'nowrap',
          }}
            onMouseEnter={e=>{ e.currentTarget.style.background='rgba(52,211,153,0.32)'; e.currentTarget.style.transform='translateY(-1px)'; }}
            onMouseLeave={e=>{ e.currentTarget.style.background='linear-gradient(135deg,rgba(52,211,153,0.22),rgba(96,165,250,0.14))'; e.currentTarget.style.transform='translateY(0)'; }}
          >↻ Sync All Now</button>
        </div>
      </div>
    </>
  );
};

// ─── Layout ───────────────────────────────────────────────────────────────────
const Layout = ({ children, stats = { xp: 0, coins: 0 } }) => {
  const location = useLocation();
  const navigate = useNavigate();
  const [notifOpen, setNotifOpen] = useState(false);
  const [syncOpen,  setSyncOpen]  = useState(false);
  const [read, setRead]           = useState({});
  const notifRef = useRef(null);
  const unread   = NOTIFICATIONS.filter(n => !read[n.id]).length;

  useEffect(() => {
    const h = (e) => {
      if (notifRef.current && !notifRef.current.contains(e.target)) setNotifOpen(false);
    };
    document.addEventListener('mousedown', h);
    return () => document.removeEventListener('mousedown', h);
  }, []);

  const markAll       = () => setRead(Object.fromEntries(NOTIFICATIONS.map(n => [n.id, true])));
  const handleViewAll = () => { markAll(); setNotifOpen(false); navigate('/notifications'); };

  const menuItems = [
    { path:'/',              icon:'/dashboard.png',         label:'Dashboard' },
    { path:'/program',       icon:'/user.png',              label:'Program and Avatar customization' },
    { path:'/challenges',    icon:'/rpg-game.png',          label:'Challenges' },
    { path:'/goals',         icon:'/dart.png',              label:'Goals and Progress' },
    { path:'/activity-food', icon:'/healthy-food.png',      label:'Daily Health Log' },
    { path:'/notifications', icon:'/notification-bell.png', label:'Notifications and Report' },
    { path:'/chatbot',       icon:'/robot (1).png',         label:'Chatbot' },
  ];

  return (
    <div>
      <header className="topbar">
